const staticData = $getWorkflowStaticData('global');
if (!staticData.importedIds) { staticData.importedIds = []; }

const resp = $input.first().json;

// Detect API auth failure
if (resp.message && !resp.items) {
  const dateStr = new Date().toISOString().split('T')[0];
  throw new Error(
    `Fathom API error on ${dateStr}: "${resp.message}". ` +
    `Check credentials at Settings → Credentials → Fathom API Key. ` +
    `Last run: ${new Date().toISOString()}`
  );
}

const meetings = resp.items || [];
if (meetings.length === 0) {
  return [{ json: { hasNew: false, meetings: [] } }];
}

const newMeetings = meetings.filter(m => !staticData.importedIds.includes(String(m.recording_id)));
return [{ json: { hasNew: newMeetings.length > 0, meetings: newMeetings } }];

const summaryResp = $input.first().json;
const meeting = $('Split Into Items').item.json;
const summaryMd = (summaryResp.summary && summaryResp.summary.markdown_formatted) || '';
return [{ json: { ...meeting, _summaryMd: summaryMd } }];

const transcriptResp = $input.first().json;
const meeting = $('Attach Summary').item.json;

const rawDate = meeting.scheduled_start_time || meeting.created_at || new Date().toISOString();
const dateStr = new Date(rawDate).toISOString().split('T')[0];
const title = meeting.meeting_title || meeting.title || 'Untitled Meeting';
const safeTitle = title.toLowerCase().replace(/[^a-z0-9\s]+/g,'').trim().replace(/\s+/g,'-').substring(0,60);
const filename = dateStr + '-' + safeTitle + '.md';

// Compact summary — strip fathom timestamp links, keep text
const rawSummary = meeting._summaryMd || '';
const summaryCompact = rawSummary
  .replace(/\[([^\]]+)\]\(https:\/\/fathom\.video\/share\/[^)]+\)/g, '$1')
  .trim() || '_No summary._';

// Transcript — max 1200 chars, then truncate
const lines = (transcriptResp.transcript || []);
let transcriptText = '';
for (const line of lines) {
  const speaker = (line.speaker && line.speaker.display_name) ? line.speaker.display_name : 'Unknown';
  const words = (line.words || []).map(w => w.text).join(' ').trim();
  if (words) transcriptText += `**${speaker}**: ${words}\n\n`;
}
const transcriptSection = transcriptText.length > 1200
  ? transcriptText.substring(0, 1200).replace(/\s+$/, '') + `\n\n_[truncated — full recording: ${meeting.share_url || meeting.url || ''}]_`
  : (transcriptText || '_No transcript._');

// Action items
const actions = (meeting.action_items || []);
const actionLines = actions.length
  ? actions.map(a => `- [ ] ${typeof a === 'string' ? a : (a.description || JSON.stringify(a))}`).join('\n')
  : '- [ ] None identified';

const markdown = `# ${title}

Date: ${dateStr}
Fathom: ${meeting.share_url || meeting.url || ''}

## Summary
${summaryCompact}

## Action Items
${actionLines}

## Raw Transcript
${transcriptSection}
`;

return [{ json: {
  recording_id: meeting.recording_id,
  title,
  markdown,
  filename,
  dateStr
}}];

const item = $input.first().json;
const encoded = Buffer.from(item.markdown, 'utf8').toString('base64');
return [{
  json: { ...item },
  binary: {
    fileData: {
      data: encoded,
      mimeType: 'text/markdown',
      fileName: item.filename,
      fileExtension: 'md'
    }
  }
}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.importedIds) { staticData.importedIds = []; }
const id = String($input.first().json.recording_id);
if (!staticData.importedIds.includes(id)) { staticData.importedIds.push(id); }
return $input.all();
